firmware_template.source:
#include "ble_ota.h"
#include <BLEOTA.h>

static bool ota_active = false;
static int ota_percent = 0;

void ble_ota_setup(const char* device_name) {
  BLEOTA.begin(device_name);
  BLEOTA.setOTAProgressCallback([](uint32_t progress, uint32_t total) {
    ota_active = true;
    ota_percent = (progress * 100) / total;
    Serial.printf("[ble_ota] %d%%\n", ota_percent);
  });
  BLEOTA.setOTACompleteCallback([]() {
    Serial.println("[ble_ota] Complete — rebooting");
    ota_active = false;
    ESP.restart();
  });
  Serial.printf("[ble_ota] Ready: %s\n", device_name);
}

void ble_ota_loop() {
  BLEOTA.process();
}

bool ble_ota_in_progress() { return ota_active; }
int ble_ota_progress() { return ota_percent; }
